{
  "name": "Dan Krejci",
  "role": "Senior Backend Engineer, Payments Infrastructure",
  "scores": {
    "technical_assessment": 72,
    "system_design": 76,
    "coding_challenge": 68,
    "behavioral_interview": 88
  },
  "references": [
    {
      "referee_name": "Sandra Park",
      "relationship": "Former Engineering Manager",
      "company": "Square",
      "summary": "Dan is one of the best engineers I've ever worked with, full stop. Technically solid, but what sets him apart is his judgment. He asks the right questions, documents everything meticulously, and owns incidents like a senior leader. His teammates love working with him. I would rehire him without hesitation."
    },
    {
      "referee_name": "Felipe Guerrero",
      "relationship": "Former Peer",
      "company": "Square",
      "summary": "Honestly, Dan makes everyone around him better. He's patient, thorough, and brings a level of reliability and follow-through that's rare. Our on-call rotation was significantly less stressful with him on the team."
    }
  ],
  "recruiter_notes": "Dan was referred by a current Stripe engineer (Anika Bhat on Payments team). He has one other active offer — mid-stage at Brex. Timeline is a bit tight, may need to move within the next 10 days."
}

